13	func sampleSpoke(id, name string, hb time.Time) SpokeRecord {
14		return SpokeRecord{
15			NodeID:        id,
16			Name:          name,
17			URL:           "https://" + name + ":7743",
18			DDxVersion:    "0.42.0",
19			SchemaVersion: "1",
20			Capabilities:  []string{"beads", "runs"},
21			RegisteredAt:  time.Date(2026, 5, 2, 19, 58, 33, 0, time.UTC),
22			LastHeartbeat: hb,
23			Status:        StatusActive,
24		}
25	}
26	
27	func TestRoundTrip(t *testing.T) {
28		dir := t.TempDir()
29		path := filepath.Join(dir, "federation-state.json")
30	
31		in := NewRegistry()
32		hb := time.Date(2026, 5, 2, 20, 0, 1, 0, time.UTC)
33		if err := in.UpsertSpoke(sampleSpoke("node-1", "bragi", hb)); err != nil {
34			t.Fatalf("upsert: %v", err)
35		}
36		if err := in.UpsertSpoke(sampleSpoke("node-2", "eitri", hb)); err != nil {
37			t.Fatalf("upsert: %v", err)
38		}
39		if err := SaveStateTo(path, in); err != nil {
40			t.Fatalf("save: %v", err)
41		}
42	
43		// File contents must be valid JSON and carry schema_version.
44		raw, err := os.ReadFile(path)
45		if err != nil {
46			t.Fatalf("read: %v", err)
47		}
48		var generic map[string]any
49		if err := json.Unmarshal(raw, &generic); err != nil {
50			t.Fatalf("file is not valid json: %v", err)
51		}
52		if generic["schema_version"] != CurrentSchemaVersion {
53			t.Fatalf("missing/wrong schema_version field in file: %v", generic["schema_version"])
54		}
55	
56		// File mode must be 0600 per FEAT-026 NFR.
57		info, err := os.Stat(path)
58		if err != nil {
59			t.Fatalf("stat: %v", err)
60		}
61		if info.Mode().Perm() != 0o600 {
62			t.Fatalf("file mode = %v, want 0600", info.Mode().Perm())
63		}
64	
65		out, err := LoadStateFrom(path)
66		if err != nil {
67			t.Fatalf("load: %v", err)
68		}
69		if out.SchemaVersion != CurrentSchemaVersion {
70			t.Fatalf("schema version round-trip: got %q", out.SchemaVersion)
71		}
72		if len(out.Spokes) != 2 {
73			t.Fatalf("spoke count: got %d", len(out.Spokes))
74		}
75		if got := out.FindSpoke("node-2"); got == nil || got.Name != "eitri" {
76			t.Fatalf("spoke lookup failed: %+v", got)
77		}
78	}
