80	func TestLoadMissingFileReturnsFreshRegistry(t *testing.T) {
81		dir := t.TempDir()
82		path := filepath.Join(dir, "missing.json")
83	
84		r, err := LoadStateFrom(path)
85		if err != nil {
86			t.Fatalf("load missing: %v", err)
87		}
88		if r.SchemaVersion != CurrentSchemaVersion {
89			t.Fatalf("fresh registry schema_version: got %q", r.SchemaVersion)
90		}
91		if len(r.Spokes) != 0 {
92			t.Fatalf("fresh registry should be empty, got %d", len(r.Spokes))
93		}
94	}
