96	func TestLoadMalformedFileRecovers(t *testing.T) {
97		dir := t.TempDir()
98		path := filepath.Join(dir, "federation-state.json")
99		if err := os.WriteFile(path, []byte("not json {{{"), 0o600); err != nil {
100			t.Fatalf("write: %v", err)
101		}
102	
103		r, err := LoadStateFrom(path)
104		if err != nil {
105			t.Fatalf("load malformed: %v", err)
106		}
107		if len(r.Spokes) != 0 || r.SchemaVersion != CurrentSchemaVersion {
108			t.Fatalf("expected fresh registry, got %+v", r)
109		}
110	
111		// Corrupt file should have been quarantined, not the live path.
112		entries, err := os.ReadDir(dir)
113		if err != nil {
114			t.Fatalf("readdir: %v", err)
115		}
116		var foundQuarantine bool
117		for _, e := range entries {
118			if strings.Contains(e.Name(), ".corrupt-") {
119				foundQuarantine = true
120			}
121		}
122		if !foundQuarantine {
123			t.Fatalf("expected quarantined .corrupt-* file, got %v", entries)
124		}
125	
126		// And a subsequent save+load works cleanly.
127		r2 := NewRegistry()
128		_ = r2.UpsertSpoke(sampleSpoke("node-x", "x", time.Now().UTC()))
129		if err := SaveStateTo(path, r2); err != nil {
130			t.Fatalf("save after recovery: %v", err)
131		}
132		r3, err := LoadStateFrom(path)
133		if err != nil || len(r3.Spokes) != 1 {
134			t.Fatalf("post-recovery load: %v %+v", err, r3)
135		}
136	}
