138	func TestStatusTransitions(t *testing.T) {
139		r := NewRegistry()
140		now := time.Date(2026, 5, 2, 20, 0, 0, 0, time.UTC)
141	
142		// Fresh register, no heartbeat yet.
143		rec := sampleSpoke("node-1", "bragi", time.Time{})
144		rec.Status = StatusRegistered
145		if err := r.UpsertSpoke(rec); err != nil {
146			t.Fatalf("upsert: %v", err)
147		}
148	
149		r.ReconcileLiveness(now, 2*time.Minute)
150		if got := r.FindSpoke("node-1").Status; got != StatusRegistered {
151			t.Fatalf("zero heartbeat → registered, got %q", got)
152		}
153	
154		// Recent heartbeat → active.
155		r.FindSpoke("node-1").LastHeartbeat = now.Add(-30 * time.Second)
156		r.ReconcileLiveness(now, 2*time.Minute)
157		if got := r.FindSpoke("node-1").Status; got != StatusActive {
158			t.Fatalf("recent hb → active, got %q", got)
159		}
160	
161		// Heartbeat older than staleAfter → stale.
162		r.FindSpoke("node-1").LastHeartbeat = now.Add(-3 * time.Minute)
163		r.ReconcileLiveness(now, 2*time.Minute)
164		if got := r.FindSpoke("node-1").Status; got != StatusStale {
165			t.Fatalf("old hb → stale, got %q", got)
166		}
167	
168		// Offline status is sticky against time-based reconciliation.
169		if err := r.SetStatus("node-1", StatusOffline); err != nil {
170			t.Fatalf("set offline: %v", err)
171		}
172		r.FindSpoke("node-1").LastHeartbeat = now.Add(-1 * time.Second)
173		r.ReconcileLiveness(now, 2*time.Minute)
174		if got := r.FindSpoke("node-1").Status; got != StatusOffline {
175			t.Fatalf("offline should be sticky, got %q", got)
176		}
177	
178		// Degraded status is sticky too.
179		_ = r.SetStatus("node-1", StatusDegraded)
180		r.ReconcileLiveness(now, 2*time.Minute)
181		if got := r.FindSpoke("node-1").Status; got != StatusDegraded {
182			t.Fatalf("degraded should be sticky, got %q", got)
183		}
184	
185		// SetStatus rejects unknown values.
186		if err := r.SetStatus("node-1", SpokeStatus("bogus")); err == nil {
187			t.Fatalf("expected error for invalid status")
188		}
189		// SetStatus reports unknown node.
190		if err := r.SetStatus("nope", StatusActive); err == nil {
191			t.Fatalf("expected error for unknown node")
192		}
193	}
