195	func TestUpsertAndRemove(t *testing.T) {
196		r := NewRegistry()
197		if err := r.UpsertSpoke(SpokeRecord{NodeID: "", Name: "x"}); err == nil {
198			t.Fatalf("expected error for empty node_id")
199		}
200		if err := r.UpsertSpoke(SpokeRecord{NodeID: "a", Status: SpokeStatus("???")}); err == nil {
201			t.Fatalf("expected error for bad status on upsert")
202		}
203	
204		// Default status when omitted on upsert.
205		if err := r.UpsertSpoke(SpokeRecord{NodeID: "a", Name: "a"}); err != nil {
206			t.Fatalf("upsert: %v", err)
207		}
208		if got := r.FindSpoke("a").Status; got != StatusRegistered {
209			t.Fatalf("default status: got %q", got)
210		}
211	
212		// Replace by node_id.
213		_ = r.UpsertSpoke(SpokeRecord{NodeID: "a", Name: "a2", Status: StatusActive})
214		if r.FindSpoke("a").Name != "a2" {
215			t.Fatalf("upsert replace failed")
216		}
217		if len(r.Spokes) != 1 {
218			t.Fatalf("upsert duplicated row")
219		}
220	
221		if !r.RemoveSpoke("a") {
222			t.Fatalf("remove existing returned false")
223		}
224		if r.RemoveSpoke("a") {
225			t.Fatalf("remove missing returned true")
226		}
227	}
