229	func TestConcurrentWriteSafety(t *testing.T) {
230		dir := t.TempDir()
231		path := filepath.Join(dir, "federation-state.json")
232	
233		const n = 16
234		var wg sync.WaitGroup
235		wg.Add(n)
236		for i := 0; i < n; i++ {
237			i := i
238			go func() {
239				defer wg.Done()
240				r := NewRegistry()
241				_ = r.UpsertSpoke(SpokeRecord{
242					NodeID:        "node-" + string(rune('a'+i)),
243					Name:          "n",
244					URL:           "https://x",
245					Status:        StatusActive,
246					LastHeartbeat: time.Now().UTC(),
247				})
248				if err := SaveStateTo(path, r); err != nil {
249					t.Errorf("concurrent save: %v", err)
250				}
251			}()
252		}
253		wg.Wait()
254	
255		// File must be parseable after the storm — atomic rename guarantees this.
256		got, err := LoadStateFrom(path)
257		if err != nil {
258			t.Fatalf("load after concurrent writes: %v", err)
259		}
260		if got.SchemaVersion != CurrentSchemaVersion {
261			t.Fatalf("schema_version corrupted under concurrency: %q", got.SchemaVersion)
262		}
263		// No leftover tmpfiles.
264		entries, _ := os.ReadDir(dir)
265		for _, e := range entries {
266			if strings.HasSuffix(e.Name(), ".tmp") {
267				t.Fatalf("leftover tmpfile after concurrent saves: %s", e.Name())
268			}
269		}
270	}
