272	func TestSchemaMigrationStub(t *testing.T) {
273		// Files written without schema_version (pre-versioned) load as
274		// CurrentSchemaVersion. This is the migration stub: the read path is
275		// where future version dispatch will hook in.
276		dir := t.TempDir()
277		path := filepath.Join(dir, "federation-state.json")
278		legacy := []byte(`{"spokes":[{"node_id":"n1","name":"old","url":"https://o","status":"active","registered_at":"2026-05-02T19:58:33Z","last_heartbeat":"2026-05-02T20:00:00Z"}]}`)
279		if err := os.WriteFile(path, legacy, 0o600); err != nil {
280			t.Fatalf("write legacy: %v", err)
281		}
282		r, err := LoadStateFrom(path)
283		if err != nil {
284			t.Fatalf("load legacy: %v", err)
285		}
286		if r.SchemaVersion != CurrentSchemaVersion {
287			t.Fatalf("legacy file should default to current schema_version, got %q", r.SchemaVersion)
288		}
289		if len(r.Spokes) != 1 || r.Spokes[0].NodeID != "n1" {
